module top_module(
  input [31:0] data_in,
  input [15:0] mask,
  input enable,
  output [15:0] data_out
);reg [15:0] masked_output;

  always @(*) begin
    if (enable) begin
      masked_output = data_in & mask;
    end else begin
      masked_output = 16'b0;
    end
  end

  assign data_out = masked_output;

endmodule
